import{Keys,pressedKey}from"../lib/accessibility";import{useDOM}from"../lib/dom";import{useIsomorphicLayoutEffect}from"../lib/useIsomorphicLayoutEffect";const EVENT_OPTIONS={passive:!0,capture:!0},useGlobalEscKeyDown=(o,s)=>{const t=useDOM()["document"];useIsomorphicLayoutEffect(()=>{if(t&&o&&s){const e=e=>{pressedKey(e)===Keys.ESCAPE&&s(e)};return t.addEventListener("keydown",e,EVENT_OPTIONS),()=>{t.removeEventListener("keydown",e,EVENT_OPTIONS)}}},[o,t,s])};export{useGlobalEscKeyDown};